(function () {
  const root = window;
  const noop = function () {};
  const resolved = function (value) { return Promise.resolve(value); };
  const rejected = function (error) { return Promise.reject(error); };
  const eventListeners = {};

  function emitEvent(name, data) {
    const payload = Object.assign({ name: name }, data || {});
    try {
      const options = root.GD_OPTIONS || {};
      if (typeof options.onEvent === "function") {
        options.onEvent(payload);
      }
    } catch (_err) {}
    const queue = eventListeners[name] || [];
    for (let index = 0; index < queue.length; index += 1) {
      try {
        queue[index](payload);
      } catch (_err) {}
    }
  }

  function completeAdFlow(kind) {
    const adKind = kind === "rewarded" ? "rewarded" : "interstitial";
    emitEvent("SDK_GAME_PAUSE", { adType: adKind });
    return new Promise(function (resolve) {
      setTimeout(function () {
        emitEvent("STARTED", { adType: adKind });
        emitEvent("COMPLETE", { adType: adKind });
        emitEvent("ALL_ADS_COMPLETED", { adType: adKind });
        emitEvent("SDK_GAME_START", { adType: adKind });
        resolve({ success: true, adType: adKind, completed: true, reward: adKind === "rewarded" });
      }, 40);
    });
  }

  const sdk = {
    version: "local-standalone",
    initialized: true,
    init: function () {
      emitEvent("SDK_READY");
      return resolved({ success: true });
    },
    initialize: function () {
      emitEvent("SDK_READY");
      return resolved({ success: true });
    },
    preloadAd: function (_kind) {
      return resolved(true);
    },
    canShowAd: function (_kind) {
      return resolved(true);
    },
    requestAd: function (kind) {
      return completeAdFlow(kind);
    },
    showAd: function (kind) {
      return completeAdFlow(kind);
    },
    play: function () {
      emitEvent("SDK_GAME_START");
      return resolved(true);
    },
    pause: function () {
      emitEvent("SDK_GAME_PAUSE");
      return resolved(true);
    },
    resume: function () {
      emitEvent("SDK_GAME_START");
      return resolved(true);
    },
    cancelAd: function () {
      return completeAdFlow("interstitial");
    },
    showBanner: function () {
      return resolved(true);
    },
    hideBanner: function () {
      return resolved(true);
    },
    showLeaderBoard: function () {
      return resolved(true);
    },
    showLeaderboard: function () {
      return resolved(true);
    },
    submitScore: function () {
      return resolved(true);
    },
    getLeaderboardEntries: function () {
      return resolved([]);
    },
    addEventListener: function (name, handler) {
      if (typeof handler !== "function") {
        return;
      }
      if (!eventListeners[name]) {
        eventListeners[name] = [];
      }
      eventListeners[name].push(handler);
    },
    removeEventListener: function (name, handler) {
      if (!eventListeners[name]) {
        return;
      }
      eventListeners[name] = eventListeners[name].filter(function (item) {
        return item !== handler;
      });
    },
    trackEvent: noop,
    event: noop,
    log: noop,
  };

  root.gdsdk = sdk;
  root.GD_SDK = sdk;
  root.GameDistribution = root.GameDistribution || {};
  root.GameDistribution.init = sdk.init;
  root.GameDistribution.initialize = sdk.initialize;
  root.GameDistribution.preloadAd = sdk.preloadAd;
  root.GameDistribution.canShowAd = sdk.canShowAd;
  root.GameDistribution.showAd = sdk.showAd;
  root.GameDistribution.cancelAd = sdk.cancelAd;
  root.GameDistribution.showLeaderBoard = sdk.showLeaderBoard;
  root.GameDistribution.showLeaderboard = sdk.showLeaderboard;
  root.GameDistribution.play = sdk.play;
  root.GameDistribution.pause = sdk.pause;
  root.GameDistribution.resume = sdk.resume;
  root.__standaloneForceAdComplete = completeAdFlow;

  setTimeout(function () {
    emitEvent("SDK_READY");
  }, 0);
})();
